# script.py

import os
import json

# Definizione del percorso del file di salvataggio
SAVE_FILE = "user_input.json"

def save_text(text):
    """Salva il testo inserito dall'utente in un file JSON."""
    try:
        # Legge il contenuto esistente del file, se presente
        if os.path.exists(SAVE_FILE):
            with open(SAVE_FILE, "r", encoding="utf-8") as file:
                data = json.load(file)
        else:
            data = []

        # Aggiunge il nuovo testo alla lista
        data.append(text)

        # Salva l'elenco aggiornato
        with open(SAVE_FILE, "w", encoding="utf-8") as file:
            json.dump(data, file, ensure_ascii=False, indent=4)

        print("Testo salvato con successo.")
    except Exception as e:
        print(f"Errore durante il salvataggio: {e}")

def load_text():
    """Carica e restituisce il testo salvato."""
    try:
        if os.path.exists(SAVE_FILE):
            with open(SAVE_FILE, "r", encoding="utf-8") as file:
                data = json.load(file)
            return data
        else:
            return []
    except Exception as e:
        print(f"Errore durante il caricamento: {e}")
        return []

def main():
    """Funzione principale per gestire l'interazione con l'utente."""
    print("Benvenuto nel modulo di salvataggio testo.")
    print("Comandi disponibili:")
    print("1. Inserisci testo")
    print("2. Visualizza testi salvati")
    print("3. Esci")

    while True:
        choice = input("\nScegli un'opzione (1-3): ").strip()

        if choice == "1":
            user_text = input("Inserisci il testo da salvare: ")
            save_text(user_text)
        elif choice == "2":
            saved_texts = load_text()
            if saved_texts:
                print("\nTesti salvati:")
                for idx, text in enumerate(saved_texts, start=1):
                    print(f"{idx}. {text}")
            else:
                print("\nNessun testo salvato.")
        elif choice == "3":
            print("Uscita dal programma.")
            break
        else:
            print("Opzione non valida. Scegli tra 1, 2 o 3.")

if __name__ == "__main__":
    main()
